import React, { useCallback, useEffect, useState } from 'react';
import { useNavigate, useSearchParams } from 'react-router-dom';

import {
	ASSET_KEY,
	PARENT_KEY,
	PROJECT_KEY,
	QUERY_KEY,
	WORKSPACE_KEY,
} from './constant/keys';
import { setIds } from './documents/editor/EditorContext';
import decodeParams from './utils/decodeParams';

const HARD_CODED_QUERY_PARAM = 'eyJ3IjoicFQ5dkFMeDIzIiwicHIiOm51bGwsInBhIjpudWxsLCJhIjoiMTFjMzc5ODQtMGQzYi00YzUzLWFlZTctN2YwNTM3Y2QxZjM4In0=';
const HARD_CODED_ACCESS_TOKEN = 'eyJhbGciOiJSUzI1NiIsInR5cCIgOiAiSldUIiwia2lkIiA6ICJEN0t1VlR0eEQ3a2pUbEFkb3Q0WVFMTk90UUNEWWJGZnFEeU9URGJ3VWdjIn0..UCQe7NjvfOqHuG8QIYpInrVR-P09JcrQH6cZIqLMGI8xU0RhQCVL4e8MfYVxEAPpKyFz_0DvnXmFJXEurhEdTtDJAR1QgVV8sfwBv76z14ZC_wlZHbJR55p08PbmxxtARh2iP9Puz0yMZKURWWjyFhydrtnPMitszQs2yVVoF7BxQw0hgFpVEz9-qqlUojOrbKCAhAZGPBgICgLWMflC49GX6Ta3O1m8h77OKLn3od9wuO7eopMNUcuDSGEe8gcs4pDRhjN2FuX6HmDtH4XXtzLlvvRnCBmAbgHVcG-qTe5a9rRFyjxAiscStTQ7WNHEB3i9FKmA1pIaC5CEKYGQlQ';

function AuthRoute({ component: Component }) {
	const [valid, setValid] = useState(false);
	const isReplit = process.env.REACT_APP_IS_REPLIT === 'true';

	const [searchParams] = useSearchParams();

	const navigate = useNavigate();

	const validateSession = useCallback(() => {
		setValid(false);
		const params = decodeParams(searchParams?.get(QUERY_KEY)) || {};

		setIds({
			workspaceId: params[WORKSPACE_KEY],
			projectId: params[PROJECT_KEY],
			parentId: params[PARENT_KEY],
			assetId: params[ASSET_KEY],
		});
		setValid(true);
	}, [searchParams]);

	useEffect(() => {
		if (!searchParams.get(QUERY_KEY)) {
			if (isReplit) {

				searchParams.set(QUERY_KEY, HARD_CODED_QUERY_PARAM);
				navigate(`${window.location.pathname}?${searchParams.toString()}`);
				window.accessToken = HARD_CODED_ACCESS_TOKEN;
			} else {
				navigate('/redirect-to-home');
			}
		}
	}, [navigate, searchParams]);

	useEffect(() => {
		validateSession();
	}, [validateSession]);

	return valid && <Component />;
}

export default AuthRoute;
